```python
import errno
import hashlib
import logging
import os
import re
import shutil
import tempfile
import uuid
from pathlib import Path
from typing import Optional, Tuple

from flask import Flask, jsonify, request
from PIL import Image, ImageFile, UnidentifiedImageError
from werkzeug.exceptions import RequestEntityTooLarge
from werkzeug.utils import secure_filename


# Prevent Pillow from silently accepting truncated images.
ImageFile.LOAD_TRUNCATED_IMAGES = False

# Protect against decompression bombs.
Image.MAX_IMAGE_PIXELS = 50_000_000

UPLOAD_DIR = Path(os.environ.get("UPLOAD_DIR", "./uploads")).resolve()
MAX_UPLOAD_BYTES = 10 * 1024 * 1024
CHUNK_SIZE = 1024 * 1024
ALLOWED_MIME_TYPES = {
    "image/jpeg": ".jpg",
    "image/png": ".png",
    "image/gif": ".gif",
    "image/webp": ".webp",
}

app = Flask(__name__)
app.config["MAX_CONTENT_LENGTH"] = MAX_UPLOAD_BYTES + 4096  # Multipart overhead allowance.

logging.basicConfig(
    level=logging.INFO,
    format="%(asctime)s %(levelname)s upload request_id=%(request_id)s %(message)s",
)
logger = logging.getLogger("upload")


class UploadError(Exception):
    def __init__(self, status: int, code: str, message: str):
        super().__init__(message)
        self.status = status
        self.code = code
        self.message = message


def json_error(status: int, code: str, message: str):
    return jsonify({"ok": False, "error": {"code": code, "message": message}}), status


def detect_image_mime(header: bytes) -> Optional[str]:
    # Magic-byte validation prevents trusting spoofed Content-Type or extensions.
    if header.startswith(b"\xff\xd8\xff"):
        return "image/jpeg"

    if header.startswith(b"\x89PNG\r\n\x1a\n"):
        return "image/png"

    if header.startswith((b"GIF87a", b"GIF89a")):
        return "image/gif"

    # WebP: RIFF....WEBP
    if len(header) >= 12 and header[:4] == b"RIFF" and header[8:12] == b"WEBP":
        return "image/webp"

    return None


def sanitize_upload_filename(original: str, extension: str) -> str:
    # Handles empty names, path traversal, control chars, unicode surprises,
    # Windows reserved names, excessive length, and extension spoofing.
    original = original or "upload"
    original = original.replace("\x00", "")
    original = os.path.basename(original)

    stem = Path(original).stem
    stem = secure_filename(stem)
    stem = re.sub(r"[^A-Za-z0-9_.-]", "_", stem).strip("._-")

    if not stem:
        stem = "upload"

    reserved = {
        "CON", "PRN", "AUX", "NUL",
        "COM1", "COM2", "COM3", "COM4", "COM5", "COM6", "COM7", "COM8", "COM9",
        "LPT1", "LPT2", "LPT3", "LPT4", "LPT5", "LPT6", "LPT7", "LPT8", "LPT9",
    }
    if stem.upper() in reserved:
        stem = f"file_{stem}"

    stem = stem[:100]
    return f"{uuid.uuid4().hex}_{stem}{extension}"


def ensure_upload_dir():
    # Fails early for missing permissions or invalid upload path.
    try:
        UPLOAD_DIR.mkdir(parents=True, exist_ok=True)
    except OSError as exc:
        raise UploadError(500, "storage_unavailable", "Upload storage is unavailable.") from exc

    if not UPLOAD_DIR.is_dir():
        raise UploadError(500, "storage_unavailable", "Upload storage path is invalid.")

    if not os.access(UPLOAD_DIR, os.W_OK | os.X_OK):
        raise UploadError(500, "storage_unavailable", "Upload storage is not writable.")


def verify_stored_image(path: Path, expected_mime: str):
    # Pillow verification catches malformed, truncated, and parser-rejected images.
    try:
        with Image.open(path) as img:
            fmt = img.format

            expected_formats = {
                "image/jpeg": "JPEG",
                "image/png": "PNG",
                "image/gif": "GIF",
                "image/webp": "WEBP",
            }

            if fmt != expected_formats[expected_mime]:
                raise UploadError(
                    415,
                    "image_type_mismatch",
                    "Image content does not match its detected type.",
                )

            width, height = img.size
            if width <= 0 or height <= 0:
                raise UploadError(400, "invalid_dimensions", "Image dimensions are invalid.")

            img.verify()

    except Image.DecompressionBombError as exc:
        raise UploadError(400, "image_too_complex", "Image is too large or complex to process safely.") from exc
    except UnidentifiedImageError as exc:
        raise UploadError(415, "invalid_image", "Uploaded file is not a valid supported image.") from exc
    except OSError as exc:
        raise UploadError(400, "corrupt_image", "Uploaded image is corrupt or incomplete.") from exc


def safe_unlink(path: Optional[Path]):
    if not path:
        return

    try:
        path.unlink(missing_ok=True)
    except OSError:
        logger.warning(
            "failed_to_remove_temp_file path=%s",
            path,
            extra={"request_id": "-"},
            exc_info=True,
        )


def stream_to_temp_file(file_storage, request_id: str) -> Tuple[Path, int, str, bytes]:
    temp_path = None
    total = 0
    sha256 = hashlib.sha256()
    header = b""

    try:
        # NamedTemporaryFile with delete=False allows explicit fsync and atomic rename.
        fd, temp_name = tempfile.mkstemp(
            prefix=f".upload-{request_id}-",
            suffix=".tmp",
            dir=str(UPLOAD_DIR),
        )
        temp_path = Path(temp_name)

        with os.fdopen(fd, "wb") as out:
            while True:
                try:
                    chunk = file_storage.stream.read(CHUNK_SIZE)
                except OSError as exc:
                    # Handles client disconnects and stream read failures.
                    raise UploadError(400, "upload_interrupted", "Upload stream ended unexpectedly.") from exc

                if not chunk:
                    break

                total += len(chunk)
                if total > MAX_UPLOAD_BYTES:
                    raise UploadError(413, "file_too_large", "File exceeds the 10MB limit.")

                if len(header) < 64:
                    header += chunk[: 64 - len(header)]

                sha256.update(chunk)

                try:
                    out.write(chunk)
                except OSError as exc:
                    if exc.errno == errno.ENOSPC:
                        raise UploadError(500, "disk_full", "Upload storage is full.") from exc
                    if exc.errno in (errno.EACCES, errno.EPERM):
                        raise UploadError(500, "storage_permission_denied", "Upload storage is not writable.") from exc
                    raise UploadError(500, "storage_write_failed", "Failed to write uploaded file.") from exc

            if total == 0:
                raise UploadError(400, "empty_file", "Uploaded file is empty.")

            try:
                out.flush()
                os.fsync(out.fileno())
            except OSError as exc:
                raise UploadError(500, "storage_sync_failed", "Failed to persist uploaded file.") from exc

        return temp_path, total, sha256.hexdigest(), header

    except Exception:
        safe_unlink(temp_path)
        raise


@app.errorhandler(RequestEntityTooLarge)
def handle_large_request(exc):
    return json_error(413, "request_too_large", "Request exceeds the 10MB upload limit.")


@app.errorhandler(UploadError)
def handle_upload_error(exc: UploadError):
    return json_error(exc.status, exc.code, exc.message)


@app.route("/api/upload", methods=["POST"])
def upload_image():
    request_id = uuid.uuid4().hex
    temp_path = None
    final_path = None

    log_extra = {"request_id": request_id}

    try:
        ensure_upload_dir()

        logger.info(
            "started remote_addr=%s content_length=%s content_type=%s",
            request.remote_addr,
            request.content_length,
            request.content_type,
            extra=log_extra,
        )

        # Reject obviously oversized requests before reading.
        if request.content_length is not None and request.content_length > app.config["MAX_CONTENT_LENGTH"]:
            raise UploadError(413, "request_too_large", "Request exceeds the 10MB upload limit.")

        if not request.content_type or not request.content_type.startswith("multipart/form-data"):
            raise UploadError(400, "invalid_content_type", "Expected multipart/form-data.")

        if "file" not in request.files:
            raise UploadError(400, "missing_file", "Missing file field named 'file'.")

        if len(request.files.getlist("file")) != 1:
            raise UploadError(400, "multiple_files", "Upload exactly one file.")

        uploaded = request.files["file"]

        if not uploaded.filename:
            raise UploadError(400, "missing_filename", "Uploaded file must have a filename.")

        temp_path, size, digest, header = stream_to_temp_file(uploaded, request_id)

        detected_mime = detect_image_mime(header)
        if detected_mime not in ALLOWED_MIME_TYPES:
            raise UploadError(
                415,
                "unsupported_file_type",
                "Only JPEG, PNG, GIF, and WebP images are supported.",
            )

        # Content-Type header is advisory only, but reject explicit mismatches for visibility.
        declared_mime = uploaded.content_type
        if declared_mime and declared_mime != "application/octet-stream" and declared_mime != detected_mime:
            raise UploadError(
                415,
                "mime_type_mismatch",
                "Declared Content-Type does not match uploaded image content.",
            )

        verify_stored_image(temp_path, detected_mime)

        extension = ALLOWED_MIME_TYPES[detected_mime]
        safe_name = sanitize_upload_filename(uploaded.filename, extension)
        final_path = (UPLOAD_DIR / safe_name).resolve()

        # Prevent path traversal even after sanitization.
        if UPLOAD_DIR not in final_path.parents:
            raise UploadError(400, "invalid_filename", "Filename resolves outside upload directory.")

        try:
            # Atomic within the same filesystem. Unique UUID name prevents races.
            os.replace(temp_path, final_path)

            # Fsync directory entry so rename survives sudden power loss on POSIX.
            dir_fd = os.open(str(UPLOAD_DIR), os.O_DIRECTORY)
            try:
                os.fsync(dir_fd)
            finally:
                os.close(dir_fd)

        except OSError as exc:
            safe_unlink(temp_path)

            if exc.errno == errno.ENOSPC:
                raise UploadError(500, "disk_full", "Upload storage is full.") from exc
            if exc.errno in (errno.EACCES, errno.EPERM):
                raise UploadError(500, "storage_permission_denied", "Upload storage is not writable.") from exc
            raise UploadError(500, "storage_commit_failed", "Failed to commit uploaded file.") from exc

        logger.info(
            "succeeded filename=%s stored_as=%s size=%d mime=%s sha256=%s",
            uploaded.filename,
            final_path.name,
            size,
            detected_mime,
            digest,
            extra=log_extra,
        )

        return jsonify({
            "ok": True,
            "file": {
                "id": final_path.stem.split("_", 1)[0],
                "filename": final_path.name,
                "original_filename": uploaded.filename,
                "mime_type": detected_mime,
                "size": size,
                "sha256": digest,
            },
        }), 201

    except UploadError as exc:
        safe_unlink(temp_path)
        logger.warning(
            "failed code=%s message=%s filename=%s",
            exc.code,
            exc.message,
            getattr(request.files.get("file"), "filename", None) if request.files else None,
            extra=log_extra,
        )
        raise

    except Exception:
        safe_unlink(temp_path)
        if final_path and final_path.exists():
            safe_unlink(final_path)

        logger.exception("failed code=internal_error", extra=log_extra)
        return json_error(500, "internal_error", "Upload failed due to an internal server error.")


if __name__ == "__main__":
    ensure_upload_dir()
    app.run(host="0.0.0.0", port=8000)
